import { KnowledgeEntry } from '../../domain/knowledge/types';

export const KNOWLEDGE_ENTRIES: KnowledgeEntry[] = [{"speciesId":1,"genus":"Seed Pokémon","habitat":"grassland","captureRate":45,"growthRate":"medium-slow","eggGroups":["monster","plant"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"A strange seed was planted on its back at birth. The plant sprouts and grows with this POKéMON."},{"game":"yellow","text":"It can go for days without eating a single morsel. In the bulb on its back, it stores energy."},{"game":"gold","text":"The seed on its back is filled with nutrients. The seed grows steadily larger as its body grows."}],"source":"pokeapi"},{"speciesId":2,"genus":"Seed Pokémon","habitat":"grassland","captureRate":45,"growthRate":"medium-slow","eggGroups":["monster","plant"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"When the bulb on its back grows large, it appears to lose the ability to stand on its hind legs."},{"game":"yellow","text":"The bulb on its back grows by drawing energy. It gives off an aroma when it is ready to bloom."},{"game":"gold","text":"Exposure to sun­ light adds to its strength. Sunlight also makes the bud on its back grow larger."}],"source":"pokeapi"},{"speciesId":3,"genus":"Seed Pokémon","habitat":"grassland","captureRate":45,"growthRate":"medium-slow","eggGroups":["monster","plant"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"The plant blooms when it is absorbing solar energy. It stays on the move to seek sunlight."},{"game":"yellow","text":"The flower on its back catches the sun's rays. The sunlight is then absorbed and used for energy."},{"game":"gold","text":"By spreading the broad petals of its flower and catching the sun's rays, it fills its body with power."}],"source":"pokeapi"},{"speciesId":4,"genus":"Lizard Pokémon","habitat":"mountain","captureRate":45,"growthRate":"medium-slow","eggGroups":["monster","dragon"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Obviously prefers hot places. When it rains, steam is said to spout from the tip of its tail."},{"game":"yellow","text":"The flame at the tip of its tail makes a sound as it burns. You can only hear it in quiet places."},{"game":"gold","text":"The flame on its tail shows the strength of its life force. If it is weak, the flame also burns weakly."}],"source":"pokeapi"},{"speciesId":5,"genus":"Flame Pokémon","habitat":"mountain","captureRate":45,"growthRate":"medium-slow","eggGroups":["monster","dragon"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"When it swings its burning tail, it elevates the temperature to unbearably high levels."},{"game":"yellow","text":"Tough fights could excite this POKéMON. When excited, it may blow out bluish- white flames."},{"game":"gold","text":"It is very hot­ headed by nature, so it constantly seeks opponents. It calms down only when it wins."}],"source":"pokeapi"},{"speciesId":6,"genus":"Flame Pokémon","habitat":"mountain","captureRate":45,"growthRate":"medium-slow","eggGroups":["monster","dragon"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"black","text":"It is said that Charizard’s fire burns hotter if it has experienced harsh battles."},{"game":"red","text":"Spits fire that is hot enough to melt boulders. Known to cause forest fires unintentionally."},{"game":"yellow","text":"When expelling a blast of super hot fire, the red flame at the tip of its tail burns more intensely."}],"source":"pokeapi"},{"speciesId":7,"genus":"Tiny Turtle Pokémon","habitat":"waters-edge","captureRate":45,"growthRate":"medium-slow","eggGroups":["monster","water1"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"After birth, its back swells and hardens into a shell. Powerfully sprays foam from its mouth."},{"game":"yellow","text":"Shoots water at prey while in the water. Withdraws into its shell when in danger."},{"game":"gold","text":"The shell is soft when it is born. It soon becomes so resilient, prod­ ding fingers will bounce off it."}],"source":"pokeapi"},{"speciesId":8,"genus":"Turtle Pokémon","habitat":"waters-edge","captureRate":45,"growthRate":"medium-slow","eggGroups":["monster","water1"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Often hides in water to stalk unwary prey. For swimming fast, it moves its ears to maintain balance."},{"game":"yellow","text":"When tapped, this POKéMON will pull in its head, but its tail will still stick out a little bit."},{"game":"gold","text":"It is recognized as a symbol of longevity. If its shell has algae on it, that WARTORTLE is very old."}],"source":"pokeapi"},{"speciesId":9,"genus":"Shellfish Pokémon","habitat":"waters-edge","captureRate":45,"growthRate":"medium-slow","eggGroups":["monster","water1"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"A brutal POKéMON with pressurized water jets on its shell. They are used for high speed tackles."},{"game":"yellow","text":"Once it takes aim at its enemy, it blasts out water with even more force than a fire hose."},{"game":"gold","text":"It deliberately makes itself heavy so it can with­ stand the recoil of the water jets it fires."}],"source":"pokeapi"},{"speciesId":10,"genus":"Worm Pokémon","habitat":"forest","captureRate":255,"growthRate":"medium","eggGroups":["bug"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Its short feet are tipped with suction pads that enable it to tirelessly climb slopes and walls."},{"game":"yellow","text":"If you touch the feeler on top of its head, it will release a horrible stink to protect itself."},{"game":"gold","text":"For protection, it releases a horri­ ble stench from the antenna on its head to drive away enemies."}],"source":"pokeapi"},{"speciesId":11,"genus":"Cocoon Pokémon","habitat":"forest","captureRate":120,"growthRate":"medium","eggGroups":["bug"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"This POKéMON is vulnerable to attack while its shell is soft, exposing its weak and tender body."},{"game":"yellow","text":"Hardens its shell to protect itself. However, a large impact may cause it to pop out of its shell."},{"game":"gold","text":"Inside the shell, it is soft and weak as it pre­ pares to evolve. It stays motion­ less in the shell."}],"source":"pokeapi"},{"speciesId":12,"genus":"Butterfly Pokémon","habitat":"forest","captureRate":45,"growthRate":"medium","eggGroups":["bug"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"In battle, it flaps its wings at high speed to release highly toxic dust into the air."},{"game":"yellow","text":"Its wings, covered with poisonous powders, repel water. This allows it to fly in the rain."},{"game":"gold","text":"It collects honey every day. It rubs honey onto the hairs on its legs to carry it back to its nest."}],"source":"pokeapi"},{"speciesId":13,"genus":"Hairy Bug Pokémon","habitat":"forest","captureRate":255,"growthRate":"medium","eggGroups":["bug"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Often found in forests, eating leaves. It has a sharp venomous stinger on its head."},{"game":"yellow","text":"Beware of the sharp stinger on its head. It hides in grass and bushes where it eats leaves."},{"game":"gold","text":"Its poison stinger is very powerful. Its bright-colored body is intended to warn off its enemies."}],"source":"pokeapi"},{"speciesId":14,"genus":"Cocoon Pokémon","habitat":"forest","captureRate":120,"growthRate":"medium","eggGroups":["bug"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Almost incapable of moving, this POKéMON can only harden its shell to protect itself from predators."},{"game":"yellow","text":"Able to move only slightly. When endangered, it may stick out its stinger and poison its enemy."},{"game":"gold","text":"Although it is a cocoon, it can move a little. It can extend its poison barb if it is attacked."}],"source":"pokeapi"},{"speciesId":15,"genus":"Poison Bee Pokémon","habitat":"forest","captureRate":45,"growthRate":"medium","eggGroups":["bug"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Flies at high speed and attacks using its large venomous stingers on its forelegs and tail."},{"game":"yellow","text":"It has 3 poisonous stingers on its forelegs and its tail. They are used to jab its enemy repeatedly."},{"game":"gold","text":"It can take down any opponent with its powerful poi­ son stingers. It sometimes attacks in swarms."}],"source":"pokeapi"},{"speciesId":16,"genus":"Tiny Bird Pokémon","habitat":"forest","captureRate":255,"growthRate":"medium-slow","eggGroups":["flying"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"A common sight in forests and woods. It flaps its wings at ground level to kick up blinding sand."},{"game":"yellow","text":"Very docile. If attacked, it will often kick up sand to protect itself rather than fight back."},{"game":"gold","text":"It usually hides in tall grass. Be­ cause it dislikes fighting, it pro­ tects itself by kicking up sand."}],"source":"pokeapi"},{"speciesId":17,"genus":"Bird Pokémon","habitat":"forest","captureRate":120,"growthRate":"medium-slow","eggGroups":["flying"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Very protective of its sprawling territorial area, this POKéMON will fiercely peck at any intruder."},{"game":"yellow","text":"This POKéMON is full of vitality. It constantly flies around its large territory in search of prey."},{"game":"gold","text":"It has outstanding vision. However high it flies, it is able to distin­ guish the move­ ments of its prey."}],"source":"pokeapi"},{"speciesId":18,"genus":"Bird Pokémon","habitat":"forest","captureRate":45,"growthRate":"medium-slow","eggGroups":["flying"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"When hunting, it skims the surface of water at high speed to pick off unwary prey such as MAGIKARP."},{"game":"yellow","text":"This POKéMON flies at Mach 2 speed, seeking prey. Its large talons are feared as wicked weapons."},{"game":"gold","text":"Its well-developed chest muscles make it strong enough to whip up a gusty windstorm with just a few flaps."}],"source":"pokeapi"},{"speciesId":19,"genus":"Mouse Pokémon","habitat":"grassland","captureRate":255,"growthRate":"medium","eggGroups":["ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"silver","text":"Living wherever there is food available, it ceaselessly scav­ enges for edibles the entire day."},{"game":"red","text":"Bites anything when it attacks. Small and very quick, it is a common sight in many places."},{"game":"yellow","text":"Will chew on any­ thing with its fangs. If you see one, it is certain that 40 more live in the area."}],"source":"pokeapi"},{"speciesId":20,"genus":"Mouse Pokémon","habitat":"grassland","captureRate":127,"growthRate":"medium","eggGroups":["ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"It uses its whis­ kers to maintain its balance. It apparently slows down if they are cut off."},{"game":"yellow","text":"Its hind feet are webbed. They act as flippers, so it can swim in rivers and hunt for prey."},{"game":"gold","text":"Gnaws on anything with its tough fangs. It can even topple concrete buildings by gnaw­ ing on them."}],"source":"pokeapi"},{"speciesId":21,"genus":"Tiny Bird Pokémon","habitat":"rough-terrain","captureRate":255,"growthRate":"medium","eggGroups":["flying"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Eats bugs in grassy areas. It has to flap its short wings at high speed to stay airborne."},{"game":"yellow","text":"Inept at flying high. However, it can fly around very fast to protect its ter­ ritory."},{"game":"gold","text":"It flaps its short wings to flush out insects from tall grass. It then plucks them with its stubby beak."}],"source":"pokeapi"},{"speciesId":22,"genus":"Beak Pokémon","habitat":"rough-terrain","captureRate":90,"growthRate":"medium","eggGroups":["flying"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"With its huge and magnificent wings, it can keep aloft without ever having to land for rest."},{"game":"yellow","text":"A POKéMON that dates back many years. If it senses danger, it flies high and away, instantly."},{"game":"gold","text":"It shoots itself suddenly high into the sky, then plummets down in one fell swoop to strike its prey."}],"source":"pokeapi"},{"speciesId":23,"genus":"Snake Pokémon","habitat":"grassland","captureRate":255,"growthRate":"medium","eggGroups":["ground","dragon"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Moves silently and stealthily. Eats the eggs of birds, such as PIDGEY and SPEAROW, whole."},{"game":"yellow","text":"The older it gets, the longer it grows. At night, it wraps its long body around tree branches to rest."},{"game":"gold","text":"It can freely de­ tach its jaw to swallow large prey whole. It can be­ come too heavy to move, however."}],"source":"pokeapi"},{"speciesId":24,"genus":"Cobra Pokémon","habitat":"grassland","captureRate":90,"growthRate":"medium","eggGroups":["ground","dragon"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"It is rumored that the ferocious warning markings on its belly differ from area to area."},{"game":"yellow","text":"The frightening patterns on its belly have been studied. Six variations have been confirmed."},{"game":"gold","text":"Transfixing prey with the face-like pattern on its belly, it binds and poisons the frightened victim."}],"source":"pokeapi"},{"speciesId":25,"genus":"Mouse Pokémon","habitat":"forest","captureRate":190,"growthRate":"medium","eggGroups":["ground","fairy"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"When several of these POKéMON gather, their electricity could build and cause lightning storms."},{"game":"yellow","text":"It keeps its tail raised to monitor its surroundings. If you yank its tail, it will try to bite you."},{"game":"gold","text":"This intelligent POKéMON roasts hard BERRIES with electricity to make them tender enough to eat."}],"source":"pokeapi"},{"speciesId":26,"genus":"Mouse Pokémon","habitat":"forest","captureRate":75,"growthRate":"medium","eggGroups":["ground","fairy"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Its long tail serves as a ground to protect itself from its own high voltage power."},{"game":"yellow","text":"When electricity builds up inside its body, it becomes feisty. It also glows in the dark."},{"game":"gold","text":"When its electric­ ity builds, its muscles are stimu­ lated, and it be­ comes more aggres­ sive than usual."}],"source":"pokeapi"},{"speciesId":27,"genus":"Mouse Pokémon","habitat":"rough-terrain","captureRate":255,"growthRate":"medium","eggGroups":["ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Burrows deep underground in arid locations far from water. It only emerges to hunt for food."},{"game":"yellow","text":"Its body is dry. When it gets cold at night, its hide is said to become coated with a fine dew."},{"game":"gold","text":"If it fell from a great height, this POKéMON could save itself by rolling into a ball and bouncing."}],"source":"pokeapi"},{"speciesId":28,"genus":"Mouse Pokémon","habitat":"rough-terrain","captureRate":90,"growthRate":"medium","eggGroups":["ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Curls up into a spiny ball when threatened. It can roll while curled up to attack or escape."},{"game":"yellow","text":"It is skilled at slashing enemies with its claws. If broken, they start to grow back in a day."},{"game":"gold","text":"In an attempt to hide itself, it will run around at top speed to kick up a blinding dust storm."}],"source":"pokeapi"},{"speciesId":29,"genus":"Poison Pin Pokémon","habitat":"grassland","captureRate":235,"growthRate":"medium-slow","eggGroups":["monster","ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Although small, its venomous barbs render this POKéMON dangerous. The female has smaller horns."},{"game":"yellow","text":"A mild-mannered POKéMON that does not like to fight. Beware, its small horns secrete venom."},{"game":"gold","text":"The poison hidden in its small horn is extremely po­ tent. Even a tiny scratch can have fatal results."}],"source":"pokeapi"},{"speciesId":30,"genus":"Poison Pin Pokémon","habitat":"grassland","captureRate":120,"growthRate":"medium-slow","eggGroups":["no-eggs"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"The female's horn develops slowly. Prefers physical attacks such as clawing and biting."},{"game":"yellow","text":"When resting deep in its burrow, its thorns always retract. This is proof that it is relaxed."},{"game":"gold","text":"When feeding its young, it first chews and tender­ izes the food, then spits it out for the offspring."}],"source":"pokeapi"},{"speciesId":31,"genus":"Drill Pokémon","habitat":"grassland","captureRate":45,"growthRate":"medium-slow","eggGroups":["no-eggs"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Its hard scales provide strong protection. It uses its hefty bulk to execute powerful moves."},{"game":"yellow","text":"Tough scales cover the sturdy body of this POKéMON. It appears that the scales grow in cycles."},{"game":"gold","text":"Its body is cover­ ed with needle- like scales. It never shows signs of shrinking from any attack."}],"source":"pokeapi"},{"speciesId":32,"genus":"Poison Pin Pokémon","habitat":"grassland","captureRate":235,"growthRate":"medium-slow","eggGroups":["monster","ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Stiffens its ears to sense danger. The larger its horns, the more powerful its secreted venom."},{"game":"yellow","text":"Its large ears are always kept upright. If it senses danger, it will attack with a poisonous sting."},{"game":"gold","text":"It is small, but its horn is filled with poison. It charges then stabs with the horn to inject poison."}],"source":"pokeapi"},{"speciesId":33,"genus":"Poison Pin Pokémon","habitat":"grassland","captureRate":120,"growthRate":"medium-slow","eggGroups":["monster","ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"An aggressive POKéMON that is quick to attack. The horn on its head secretes a powerful venom."},{"game":"yellow","text":"Its horns contain venom. If they are stabbed into an enemy, the impact makes the poison leak out."},{"game":"gold","text":"It raises its big ears to check its surroundings. If it senses any­ thing, it attacks immediately."}],"source":"pokeapi"},{"speciesId":34,"genus":"Drill Pokémon","habitat":"grassland","captureRate":45,"growthRate":"medium-slow","eggGroups":["monster","ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"It uses its powerful tail in battle to smash, constrict, then break the prey's bones."},{"game":"yellow","text":"Its steel-like hide adds to its powerful tackle. Its horns are so hard, they can pierce a diamond."},{"game":"gold","text":"It swings its big tail around during battle. If its foe flinches, it will charge with its sturdy body."}],"source":"pokeapi"},{"speciesId":35,"genus":"Fairy Pokémon","habitat":"mountain","captureRate":150,"growthRate":"fast","eggGroups":["fairy"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Its magical and cute appeal has many admirers. It is rare and found only in certain areas."},{"game":"yellow","text":"Adored for their cute looks and playfulness. They are thought to be rare, as they do not appear often."},{"game":"gold","text":"The moonlight that it stores in the wings on its back apparently gives it the ability to float in midair."}],"source":"pokeapi"},{"speciesId":36,"genus":"Fairy Pokémon","habitat":"mountain","captureRate":25,"growthRate":"fast","eggGroups":["fairy"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"A timid fairy POKéMON that is rarely seen. It will run and hide the moment it senses people."},{"game":"yellow","text":"They appear to be very protective of their own world. It is a kind of fairy, rarely seen by people."},{"game":"gold","text":"With its acute hearing, it can pick up sounds from far away. It usually hides in quiet places."}],"source":"pokeapi"},{"speciesId":37,"genus":"Fox Pokémon","habitat":"grassland","captureRate":190,"growthRate":"medium","eggGroups":["ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"At the time of birth, it has just one tail. The tail splits from its tip as it grows older."},{"game":"yellow","text":"Both its fur and its tails are beautiful. As it grows, the tails split and form more tails."},{"game":"gold","text":"As it develops, its single white tail gains color and splits into six. It is quite warm and cuddly."}],"source":"pokeapi"},{"speciesId":38,"genus":"Fox Pokémon","habitat":"grassland","captureRate":75,"growthRate":"medium","eggGroups":["ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Very smart and very vengeful. Grabbing one of its many tails could result in a 1000-year curse."},{"game":"yellow","text":"According to an enduring legend, 9 noble saints were united and reincarnated as this POKéMON."},{"game":"gold","text":"Some legends claim that each of its nine tails has its own unique type of special mystical power."}],"source":"pokeapi"},{"speciesId":39,"genus":"Balloon Pokémon","habitat":"grassland","captureRate":170,"growthRate":"fast","eggGroups":["fairy"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"When its huge eyes light up, it sings a mysteriously soothing melody that lulls its enemies to sleep."},{"game":"yellow","text":"Uses its alluring eyes to enrapture its foe. It then sings a pleasing melody that lulls the foe to sleep."},{"game":"gold","text":"If it inflates to SING a lullaby, it can perform longer and cause sure drowsiness in its audience."}],"source":"pokeapi"},{"speciesId":40,"genus":"Balloon Pokémon","habitat":"grassland","captureRate":50,"growthRate":"fast","eggGroups":["fairy"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"The body is soft and rubbery. When angered, it will suck in air and inflate itself to an enormous size."},{"game":"yellow","text":"Its body is full of elasticity. By inhaling deeply, it can continue to inflate itself without limit."},{"game":"gold","text":"Their fur feels so good that if two of them snuggle together, they won't want to be separated."}],"source":"pokeapi"},{"speciesId":41,"genus":"Bat Pokémon","habitat":"cave","captureRate":255,"growthRate":"medium","eggGroups":["flying"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"y","text":"It has no eyes. Instead, it relies on its ultrasonic cries for echolocation to flit about in darkness."},{"game":"red","text":"Forms colonies in perpetually dark places. Uses ultrasonic waves to identify and approach targets."},{"game":"yellow","text":"Emits ultrasonic cries while it flies. They act as a sonar used to check for ob­ jects in its way."}],"source":"pokeapi"},{"speciesId":42,"genus":"Bat Pokémon","habitat":"cave","captureRate":90,"growthRate":"medium","eggGroups":["flying"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Once it strikes, it will not stop draining energy from the victim even if it gets too heavy to fly."},{"game":"yellow","text":"It attacks in a stealthy manner, without warning. Its sharp fangs are used to bite and suck blood."},{"game":"gold","text":"However hard its victim's hide may be, it punctures with sharp fangs and gorges itself with blood."}],"source":"pokeapi"},{"speciesId":43,"genus":"Weed Pokémon","habitat":"grassland","captureRate":255,"growthRate":"medium-slow","eggGroups":["plant"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"During the day, it keeps its face buried in the ground. At night, it wanders around sowing its seeds."},{"game":"yellow","text":"It may be mistaken for a clump of weeds. If you try to yank it out of the ground, it shrieks horribly."},{"game":"gold","text":"Awakened by moon­ light, it roams actively at night. In the day, it stays quietly underground."}],"source":"pokeapi"},{"speciesId":44,"genus":"Weed Pokémon","habitat":"grassland","captureRate":120,"growthRate":"medium-slow","eggGroups":["plant"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"The fluid that oozes from its mouth isn't drool. It is a nectar that is used to attract prey."},{"game":"yellow","text":"Smells incredibly foul! However, around 1 out of 1,000 people enjoy sniffing its nose- bending stink."},{"game":"gold","text":"What appears to be drool is actually sweet honey. It is very sticky and clings stubbornly if touched."}],"source":"pokeapi"},{"speciesId":45,"genus":"Flower Pokémon","habitat":"grassland","captureRate":45,"growthRate":"medium-slow","eggGroups":["plant"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"The larger its petals, the more toxic pollen it contains. Its big head is heavy and hard to hold up."},{"game":"yellow","text":"Flaps its broad flower petals to scatter its poisonous pollen. The flapping sound is very loud."},{"game":"gold","text":"It has the world's largest petals. With every step, the petals shake out heavy clouds of toxic pollen."}],"source":"pokeapi"},{"speciesId":46,"genus":"Mushroom Pokémon","habitat":"forest","captureRate":190,"growthRate":"medium","eggGroups":["bug","plant"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Burrows to suck tree roots. The mushrooms on its back grow by draw­ ing nutrients from the bug host."},{"game":"yellow","text":"Burrows under the ground to gnaw on tree roots. The mushrooms on its back absorb most of the nutrition."},{"game":"gold","text":"It is doused with mushroom spores when it is born. As its body grows, mushrooms sprout from its back."}],"source":"pokeapi"},{"speciesId":47,"genus":"Mushroom Pokémon","habitat":"forest","captureRate":75,"growthRate":"medium","eggGroups":["bug","plant"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"gold","text":"It stays mostly in dark, damp places, the preference not of the bug, but of the big mush­ rooms on its back."},{"game":"silver","text":"The larger the mushroom on its back grows, the stronger the mush­ room spores it scatters."},{"game":"red","text":"A host-parasite pair in which the parasite mushroom has taken over the host bug. Prefers damp places."}],"source":"pokeapi"},{"speciesId":48,"genus":"Insect Pokémon","habitat":"forest","captureRate":190,"growthRate":"medium","eggGroups":["bug"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"white-2","text":"Its big eyes are actually clusters of tiny eyes. At night, its kind is drawn by light."},{"game":"red","text":"Lives in the shadows of tall trees where it eats insects. It is attracted by light at night."},{"game":"yellow","text":"Its large eyes act as radars. In a bright place, you can see that they are clusters of many tiny eyes."}],"source":"pokeapi"},{"speciesId":49,"genus":"Poison Moth Pokémon","habitat":"forest","captureRate":75,"growthRate":"medium","eggGroups":["bug"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"The dust-like scales covering its wings are color coded to indicate the kinds of poison it has."},{"game":"yellow","text":"The powdery scales on its wings are hard to remove. They also contain poison that leaks out on contact."},{"game":"gold","text":"When it attacks, it flaps its large wings violently to scatter its poi­ sonous powder all around."}],"source":"pokeapi"},{"speciesId":50,"genus":"Mole Pokémon","habitat":"cave","captureRate":255,"growthRate":"medium","eggGroups":["ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Lives about one yard underground where it feeds on plant roots. It sometimes appears above ground."},{"game":"yellow","text":"It prefers dark places. It spends most of its time underground, though it may pop up in caves."},{"game":"gold","text":"Its skin is very thin. If it is exposed to light, its blood heats up, causing it to grow weak."}],"source":"pokeapi"},{"speciesId":51,"genus":"Mole Pokémon","habitat":"cave","captureRate":50,"growthRate":"medium","eggGroups":["ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"A team of DIGLETT triplets. It triggers huge earthquakes by burrowing 60 miles underground."},{"game":"yellow","text":"A team of triplets that can burrow over 60 MPH. Due to this, some people think it's an earthquake."},{"game":"gold","text":"Its three heads bob separately up and down to loosen the soil nearby, making it easier for it to burrow."}],"source":"pokeapi"},{"speciesId":52,"genus":"Scratch Cat Pokémon","habitat":"urban","captureRate":255,"growthRate":"medium","eggGroups":["ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Adores circular objects. Wanders the streets on a nightly basis to look for dropped loose change."},{"game":"yellow","text":"Appears to be more active at night. It loves round and shiny things. It can't stop from picking them up."},{"game":"gold","text":"It is fascinated by round objects. It can't stop playing with them until it tires and falls asleep."}],"source":"pokeapi"},{"speciesId":53,"genus":"Classy Cat Pokémon","habitat":"urban","captureRate":90,"growthRate":"medium","eggGroups":["ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Although its fur has many admirers, it is tough to raise as a pet because of its fickle meanness."},{"game":"yellow","text":"The gem in its forehead glows on its own! It walks with all the grace and elegance of a proud queen."},{"game":"gold","text":"Many adore it for its sophisticated air. However, it will lash out and scratch for little reason."}],"source":"pokeapi"},{"speciesId":54,"genus":"Duck Pokémon","habitat":"waters-edge","captureRate":190,"growthRate":"medium","eggGroups":["water1","ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"While lulling its enemies with its vacant look, this wily POKéMON will use psychokinetic powers."},{"game":"yellow","text":"Always tormented by headaches. It uses psychic powers, but it is not known if it intends to do so."},{"game":"gold","text":"It has mystical powers but doesn't recall that it has used them. That is why it always looks puzzled."}],"source":"pokeapi"},{"speciesId":55,"genus":"Duck Pokémon","habitat":"waters-edge","captureRate":75,"growthRate":"medium","eggGroups":["water1","ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Often seen swim­ ming elegantly by lake shores. It is often mistaken for the Japanese monster, Kappa."},{"game":"yellow","text":"Its slim and long limbs end in broad flippers. They are used for swim­ ming gracefully in lakes."},{"game":"gold","text":"When it swims at full speed using its long, webbed limbs, its fore­ head somehow be­ gins to glow."}],"source":"pokeapi"},{"speciesId":56,"genus":"Pig Monkey Pokémon","habitat":"mountain","captureRate":190,"growthRate":"medium","eggGroups":["ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Extremely quick to anger. It could be docile one moment then thrashing away the next instant."},{"game":"yellow","text":"An agile POKéMON that lives in trees. It angers easily and will not hesitate to attack anything."},{"game":"gold","text":"It is extremely ill-tempered. Groups of them will attack any handy target for no reason."}],"source":"pokeapi"},{"speciesId":57,"genus":"Pig Monkey Pokémon","habitat":"mountain","captureRate":75,"growthRate":"medium","eggGroups":["ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Always furious and tenacious to boot. It will not abandon chasing its quarry until it is caught."},{"game":"yellow","text":"It stops being angry only when nobody else is around. To view this moment is very difficult."},{"game":"gold","text":"If approached while asleep, it may awaken and angrily give chase in a groggy state of semi-sleep."}],"source":"pokeapi"},{"speciesId":58,"genus":"Puppy Pokémon","habitat":"grassland","captureRate":190,"growthRate":"slow","eggGroups":["ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Very protective of its territory. It will bark and bite to repel intruders from its space."},{"game":"yellow","text":"A POKéMON with a friendly nature. However, it will bark fiercely at anything invading its territory."},{"game":"gold","text":"It has a brave and trustworthy na­ ture. It fear­ lessly stands up to bigger and stronger foes."}],"source":"pokeapi"},{"speciesId":59,"genus":"Legendary Pokémon","habitat":"grassland","captureRate":75,"growthRate":"slow","eggGroups":["ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"A POKéMON that has been admired since the past for its beauty. It runs agilely as if on wings."},{"game":"yellow","text":"A legendary POKé­ MON in China. Many people are charmed by its grace and beauty while running."},{"game":"gold","text":"This legendary Chinese POKEMON is considered magnif­ icent. Many people are enchanted by its grand mane."}],"source":"pokeapi"},{"speciesId":60,"genus":"Tadpole Pokémon","habitat":"waters-edge","captureRate":255,"growthRate":"medium-slow","eggGroups":["water1"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Its newly grown legs prevent it from running. It appears to prefer swimming than trying to stand."},{"game":"yellow","text":"The direction of the spiral on the belly differs by area. It is more adept at swimming than walking."},{"game":"gold","text":"Because it is in­ ept at walking on its newly grown legs, it always swims around in water."}],"source":"pokeapi"},{"speciesId":61,"genus":"Tadpole Pokémon","habitat":"waters-edge","captureRate":120,"growthRate":"medium-slow","eggGroups":["water1"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Capable of living in or out of water. When out of water, it sweats to keep its body slimy."},{"game":"yellow","text":"Under attack, it uses its belly spiral to put the foe to sleep. It then makes its escape."},{"game":"gold","text":"The swirl on its belly subtly un­ dulates. Staring at it may gradual­ ly cause drowsi­ ness."}],"source":"pokeapi"},{"speciesId":62,"genus":"Tadpole Pokémon","habitat":"waters-edge","captureRate":45,"growthRate":"medium-slow","eggGroups":["water1"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"An adept swimmer at both the front crawl and breast stroke. Easily overtakes the best human swimmers."},{"game":"yellow","text":"Swims powerfully using all the muscles in its body. It can even overtake champion swimmers."},{"game":"gold","text":"This strong and skilled swimmer is even capable of crossing the Pacific Ocean just by kicking."}],"source":"pokeapi"},{"speciesId":63,"genus":"Psi Pokémon","habitat":"urban","captureRate":200,"growthRate":"medium-slow","eggGroups":["humanshape"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Using its ability to read minds, it will identify impending danger and TELEPORT to safety."},{"game":"yellow","text":"Sleeps 18 hours a day. If it senses danger, it will teleport itself to safety even as it sleeps."},{"game":"gold","text":"It senses impend­ ing attacks and TELEPORTS away to safety before the actual attacks can strike."}],"source":"pokeapi"},{"speciesId":64,"genus":"Psi Pokémon","habitat":"urban","captureRate":100,"growthRate":"medium-slow","eggGroups":["humanshape"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"It emits special alpha waves from its body that induce headaches just by being close by."},{"game":"yellow","text":"Many odd things happen if this POKéMON is close by. For example, it makes clocks run backwards."},{"game":"gold","text":"It possesses strong spiritual power. The more danger it faces, the stronger its psychic power."}],"source":"pokeapi"},{"speciesId":65,"genus":"Psi Pokémon","habitat":"urban","captureRate":50,"growthRate":"medium-slow","eggGroups":["humanshape"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Its brain can out­ perform a super­ computer. Its intelligence quotient is said to be 5,000."},{"game":"yellow","text":"A POKéMON that can memorize anything. It never forgets what it learns-- that's why this POKéMON is smart."},{"game":"gold","text":"Closing both its eyes heightens all its other senses. This enables it to use its abilities to their extremes."}],"source":"pokeapi"},{"speciesId":66,"genus":"Superpower Pokémon","habitat":"mountain","captureRate":180,"growthRate":"medium-slow","eggGroups":["humanshape"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Loves to build its muscles. It trains in all styles of martial arts to become even stronger."},{"game":"yellow","text":"Very powerful in spite of its small size. Its mastery of many types of martial arts makes it very tough."},{"game":"gold","text":"Always brimming with power, it passes time by lifting boulders. Doing so makes it even stronger."}],"source":"pokeapi"},{"speciesId":67,"genus":"Superpower Pokémon","habitat":"mountain","captureRate":90,"growthRate":"medium-slow","eggGroups":["humanshape"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"white-2","text":"It happily carries heavy cargo to toughen up. It willingly does hard work for people."},{"game":"red","text":"Its muscular body is so powerful, it must wear a power save belt to be able to regulate its motions."},{"game":"yellow","text":"The belt around its waist holds back its energy. Without it, this POKéMON would be unstoppable."}],"source":"pokeapi"},{"speciesId":68,"genus":"Superpower Pokémon","habitat":"mountain","captureRate":45,"growthRate":"medium-slow","eggGroups":["humanshape"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Using its heavy muscles, it throws powerful punches that can send the victim clear over the horizon."},{"game":"yellow","text":"One arm alone can move mountains. Using all four arms, this POKéMON fires off awesome punches."},{"game":"gold","text":"It quickly swings its four arms to rock its opponents with ceaseless punches and chops from all angles."}],"source":"pokeapi"},{"speciesId":69,"genus":"Flower Pokémon","habitat":"forest","captureRate":255,"growthRate":"medium-slow","eggGroups":["plant"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"A carnivorous POKéMON that traps and eats bugs. It uses its root feet to soak up needed moisture."},{"game":"yellow","text":"Prefers hot and humid places. It ensnares tiny insects with its vines and devours them."},{"game":"gold","text":"Even though its body is extremely skinny, it is blindingly fast when catching its prey."}],"source":"pokeapi"},{"speciesId":70,"genus":"Flycatcher Pokémon","habitat":"forest","captureRate":120,"growthRate":"medium-slow","eggGroups":["plant"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"white-2","text":"A Pokémon that appears to be a plant. It captures unwary prey by dousing them with a toxic powder."},{"game":"red","text":"It spits out POISONPOWDER to immobilize the enemy and then finishes it with a spray of ACID."},{"game":"yellow","text":"When hungry, it swallows anything that moves. Its hapless prey is melted inside by strong acids."}],"source":"pokeapi"},{"speciesId":71,"genus":"Flycatcher Pokémon","habitat":"forest","captureRate":45,"growthRate":"medium-slow","eggGroups":["plant"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Said to live in huge colonies deep in jungles, although no one has ever returned from there."},{"game":"yellow","text":"Lures prey with the sweet aroma of honey. Swallowed whole, the prey is melted in a day, bones and all."},{"game":"gold","text":"ACID that has dis­ solved many prey becomes sweeter, making it even more effective at attracting prey."}],"source":"pokeapi"},{"speciesId":72,"genus":"Jellyfish Pokémon","habitat":"sea","captureRate":190,"growthRate":"slow","eggGroups":["water3"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Drifts in shallow seas. Anglers who hook them by accident are often punished by its stinging acid."},{"game":"yellow","text":"It can sometimes be found all dry and shriveled up on a beach. Toss it back into the sea to revive it."},{"game":"gold","text":"When the tide goes out, dehydrated TENTACOOL remains can be found washed up on the shore."}],"source":"pokeapi"},{"speciesId":73,"genus":"Jellyfish Pokémon","habitat":"sea","captureRate":60,"growthRate":"slow","eggGroups":["water3"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"The tentacles are normally kept short. On hunts, they are extended to ensnare and immobilize prey."},{"game":"yellow","text":"Its 80 tentacles can stretch and contract freely. They wrap around prey and weaken it with poison."},{"game":"gold","text":"Its 80 tentacles absorb water and stretch almost endlessly to CON­ STRICT its prey and enemies."}],"source":"pokeapi"},{"speciesId":74,"genus":"Rock Pokémon","habitat":"mountain","captureRate":255,"growthRate":"medium-slow","eggGroups":["mineral"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"x","text":"Found in fields and mountains. Mistaking them for boulders, people often step or trip on them."},{"game":"yellow","text":"Commonly found near mountain trails, etc. If you step on one by accident, it gets angry."},{"game":"gold","text":"Most people may not notice, but a closer look should reveal that there are many GEODUDE around."}],"source":"pokeapi"},{"speciesId":75,"genus":"Rock Pokémon","habitat":"mountain","captureRate":120,"growthRate":"medium-slow","eggGroups":["mineral"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Rolls down slopes to move. It rolls over any obstacle without slowing or changing its direction."},{"game":"yellow","text":"Often seen rolling down mountain trails. Obstacles are just things to roll straight over, not avoid."},{"game":"gold","text":"With a free and uncaring nature, it doesn't mind if pieces break off while it rolls down mountains."}],"source":"pokeapi"},{"speciesId":76,"genus":"Megaton Pokémon","habitat":"mountain","captureRate":45,"growthRate":"medium-slow","eggGroups":["mineral"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Its boulder-like body is extremely hard. It can easily withstand dynamite blasts without damage."},{"game":"yellow","text":"Once it sheds its skin, its body turns tender and whitish. Its hide hardens when it's exposed to air."},{"game":"gold","text":"It sheds its skin once a year. The discarded shell immediately hard­ ens and crumbles away."}],"source":"pokeapi"},{"speciesId":77,"genus":"Fire Horse Pokémon","habitat":"grassland","captureRate":190,"growthRate":"medium","eggGroups":["ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Its hooves are 10 times harder than diamonds. It can trample anything completely flat in little time."},{"game":"yellow","text":"Capable of jumping incredibly high. Its hooves and sturdy legs absorb the impact of a hard landing."},{"game":"gold","text":"It is a weak run­ ner immediately after birth. It gradually becomes faster by chasing after its parents."}],"source":"pokeapi"},{"speciesId":78,"genus":"Fire Horse Pokémon","habitat":"grassland","captureRate":60,"growthRate":"medium","eggGroups":["ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Very competitive, this POKéMON will chase anything that moves fast in the hopes of racing it."},{"game":"yellow","text":"Just loves to run. If it sees some­ thing faster than itself, it will give chase at top speed."},{"game":"gold","text":"At full gallop, its four hooves barely touch the ground because it moves so incredi­ bly fast."}],"source":"pokeapi"},{"speciesId":79,"genus":"Dopey Pokémon","habitat":"waters-edge","captureRate":190,"growthRate":"medium","eggGroups":["monster","water1"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"crystal","text":"It is always so absent-minded that it won't react, even if its flavorful tail is bitten."},{"game":"red","text":"Incredibly slow and dopey. It takes 5 seconds for it to feel pain when under attack."},{"game":"yellow","text":"Incredibly slow and sluggish. It is quite content to loll about without worrying about the time."}],"source":"pokeapi"},{"speciesId":80,"genus":"Hermit Crab Pokémon","habitat":"waters-edge","captureRate":75,"growthRate":"medium","eggGroups":["monster","water1"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"The SHELLDER that is latched onto SLOWPOKE's tail is said to feed on the host's left over scraps."},{"game":"yellow","text":"Lives lazily by the sea. If the SHELLDER on its tail comes off, it becomes a SLOWPOKE again."},{"game":"gold","text":"If the tail-biting SHELLDER is thrown off in a harsh battle, it reverts to being an ordi­ nary SLOWPOKE."}],"source":"pokeapi"},{"speciesId":81,"genus":"Magnet Pokémon","habitat":"rough-terrain","captureRate":190,"growthRate":"medium","eggGroups":["mineral"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Uses anti-gravity to stay suspended. Appears without warning and uses THUNDER WAVE and similar moves."},{"game":"yellow","text":"It is born with the ability to defy gravity. It floats in air on powerful electro­ magnetic waves."},{"game":"gold","text":"It is attracted by electromagnetic waves. It may approach trainers if they are using their POKéGEAR."}],"source":"pokeapi"},{"speciesId":82,"genus":"Magnet Pokémon","habitat":"rough-terrain","captureRate":60,"growthRate":"medium","eggGroups":["mineral"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Formed by several MAGNEMITEs linked together. They frequently appear when sunspots flare up."},{"game":"yellow","text":"Generates strange radio signals. It raises the tem­ perature by 3.6F degrees within 3,300 feet."},{"game":"gold","text":"Three MAGNEMITE are linked by a strong magnetic force. Earaches will occur if you get too close."}],"source":"pokeapi"},{"speciesId":83,"genus":"Wild Duck Pokémon","habitat":"grassland","captureRate":45,"growthRate":"medium","eggGroups":["flying","ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"The sprig of green onions it holds is its weapon. It is used much like a metal sword."},{"game":"yellow","text":"Lives where reedy plants grow. They are rarely seen, so it's thought their numbers are decreasing."},{"game":"gold","text":"If anyone tries to disturb where the essential plant sticks grow, it uses its own stick to thwart them."}],"source":"pokeapi"},{"speciesId":84,"genus":"Twin Bird Pokémon","habitat":"grassland","captureRate":190,"growthRate":"medium","eggGroups":["flying"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"A bird that makes up for its poor flying with its fast foot speed. Leaves giant footprints."},{"game":"yellow","text":"Its short wings make flying dif­ ficult. Instead, this POKéMON runs at high speed on developed legs."},{"game":"gold","text":"By alternately raising and lower­ ing its two heads, it balances itself to be more stable while running."}],"source":"pokeapi"},{"speciesId":85,"genus":"Triple Bird Pokémon","habitat":"grassland","captureRate":45,"growthRate":"medium","eggGroups":["flying"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Uses its three brains to execute complex plans. While two heads sleep, one head stays awake."},{"game":"yellow","text":"One of DODUO's 2 heads splits to form a unique species. It runs close to 40 MPH in prairies."},{"game":"gold","text":"It collects data and plans three times as wisely, but it may think too much and be­ come immobilized."}],"source":"pokeapi"},{"speciesId":86,"genus":"Sea Lion Pokémon","habitat":"sea","captureRate":190,"growthRate":"medium","eggGroups":["water1","ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"The protruding horn on its head is very hard. It is used for bashing through thick ice."},{"game":"yellow","text":"Loves freezing cold conditions. Relishes swimming in a frigid cli­ mate of around 14F degrees."},{"game":"gold","text":"Although it can't walk well on land, it is a graceful swimmer. It espe­ cially loves being in frigid seas."}],"source":"pokeapi"},{"speciesId":87,"genus":"Sea Lion Pokémon","habitat":"sea","captureRate":75,"growthRate":"medium","eggGroups":["water1","ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Stores thermal energy in its body. Swims at a steady 8 knots even in intensely cold waters."},{"game":"yellow","text":"Its entire body is a snowy-white. Unharmed by even intense cold, it swims powerfully in icy waters."},{"game":"gold","text":"Its streamlined body has little drag in water. The colder the temperature, the friskier it gets."}],"source":"pokeapi"},{"speciesId":88,"genus":"Sludge Pokémon","habitat":"urban","captureRate":190,"growthRate":"medium","eggGroups":["indeterminate"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Appears in filthy areas. Thrives by sucking up polluted sludge that is pumped out of factories."},{"game":"yellow","text":"Made of hardened sludge. It smells too putrid to touch. Even weeds won't grow in its path."},{"game":"gold","text":"As it moves, it loses bits of its body from which new GRIMER emerge. This worsens the stench around it."}],"source":"pokeapi"},{"speciesId":89,"genus":"Sludge Pokémon","habitat":"urban","captureRate":75,"growthRate":"medium","eggGroups":["indeterminate"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Thickly covered with a filthy, vile sludge. It is so toxic, even its footprints contain poison."},{"game":"yellow","text":"Smells so awful, it can cause fainting. Through degeneration, it lost its sense of smell."},{"game":"gold","text":"They love to gath­ er in smelly areas where sludge ac­ cumulates, making the stench around them worse."}],"source":"pokeapi"},{"speciesId":90,"genus":"Bivalve Pokémon","habitat":"sea","captureRate":190,"growthRate":"slow","eggGroups":["water3"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Its hard shell repels any kind of attack. It is vulnerable only when its shell is open."},{"game":"yellow","text":"The shell can withstand any attack. However, when it is open, the tender body is exposed."},{"game":"gold","text":"It swims facing backward by open­ ing and closing its two-piece shell. It is surprisingly fast."}],"source":"pokeapi"},{"speciesId":91,"genus":"Bivalve Pokémon","habitat":"sea","captureRate":60,"growthRate":"slow","eggGroups":["water3"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"When attacked, it launches its horns in quick volleys. Its innards have never been seen."},{"game":"yellow","text":"For protection, it uses its harder- than-diamonds shell. It also shoots spikes from the shell."},{"game":"gold","text":"Once it slams its shell shut, it is impossible to open, even by those with superi­ or strength."}],"source":"pokeapi"},{"speciesId":92,"genus":"Gas Pokémon","habitat":"cave","captureRate":190,"growthRate":"medium-slow","eggGroups":["indeterminate"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Almost invisible, this gaseous POKéMON cloaks the target and puts it to sleep without notice."},{"game":"yellow","text":"Said to appear in decrepit, deserted buildings. It has no real shape as it appears to be made of a gas."},{"game":"gold","text":"With its gas-like body, it can sneak into any place it desires. However, it can be blown away by wind."}],"source":"pokeapi"},{"speciesId":93,"genus":"Gas Pokémon","habitat":"cave","captureRate":90,"growthRate":"medium-slow","eggGroups":["indeterminate"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Because of its ability to slip through block walls, it is said to be from an­ other dimension."},{"game":"yellow","text":"By licking, it saps the victim's life. It causes shaking that won't stop until the victim's demise."},{"game":"gold","text":"In total darkness, where nothing is visible, HAUNTER lurks, silently stalking its next victim."}],"source":"pokeapi"},{"speciesId":94,"genus":"Shadow Pokémon","habitat":"cave","captureRate":45,"growthRate":"medium-slow","eggGroups":["indeterminate"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Under a full moon, this POKéMON likes to mimic the shadows of people and laugh at their fright."},{"game":"yellow","text":"A GENGAR is close by if you feel a sudden chill. It may be trying to lay a curse on you."},{"game":"gold","text":"It steals heat from its surround­ ings. If you feel a sudden chill, it is certain that a GENGAR appeared."}],"source":"pokeapi"},{"speciesId":95,"genus":"Rock Snake Pokémon","habitat":"cave","captureRate":45,"growthRate":"medium","eggGroups":["mineral"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"white","text":"It burrows through the ground at a speed of 50 mph while feeding on large boulders."},{"game":"black-2","text":"Opening its large mouth, it ingests massive amounts of soil and creates long tunnels."},{"game":"red","text":"As it grows, the stone portions of its body harden to become similar to a diamond, but colored black."}],"source":"pokeapi"},{"speciesId":96,"genus":"Hypnosis Pokémon","habitat":"grassland","captureRate":190,"growthRate":"medium","eggGroups":["humanshape"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Puts enemies to sleep then eats their dreams. Occasionally gets sick from eating bad dreams."},{"game":"yellow","text":"If you sleep by it all the time, it will sometimes show you dreams it has eaten in the past."},{"game":"gold","text":"If you think that you had a good dream, but you can't remember it, a DROWZEE has probably eaten it."}],"source":"pokeapi"},{"speciesId":97,"genus":"Hypnosis Pokémon","habitat":"grassland","captureRate":75,"growthRate":"medium","eggGroups":["humanshape"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"When it locks eyes with an enemy, it will use a mix of PSI moves such as HYPNOSIS and CONFUSION."},{"game":"yellow","text":"Avoid eye contact if you come across one. It will try to put you to sleep by using its pendulum."},{"game":"gold","text":"When it is very hungry, it puts humans it meets to sleep, then it feasts on their dreams."}],"source":"pokeapi"},{"speciesId":98,"genus":"River Crab Pokémon","habitat":"waters-edge","captureRate":225,"growthRate":"medium","eggGroups":["water3"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Its pincers are not only powerful weapons, they are used for balance when walking sideways."},{"game":"yellow","text":"Its pincers are superb weapons. They sometimes break off during battle, but they grow back fast."},{"game":"gold","text":"If it senses dan­ ger approaching, it cloaks itself with bubbles from its mouth so it will look bigger."}],"source":"pokeapi"},{"speciesId":99,"genus":"Pincer Pokémon","habitat":"waters-edge","captureRate":60,"growthRate":"medium","eggGroups":["water3"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"The large pincer has 10000 hp of crushing power. However, its huge size makes it unwieldy to use."},{"game":"yellow","text":"One claw grew massively and as hard as steel. It has 10,000-HP strength. However, it is too heavy."},{"game":"gold","text":"It can hardly lift its massive, overgrown pincer. The pincer's size makes it difficult to aim properly."}],"source":"pokeapi"},{"speciesId":100,"genus":"Ball Pokémon","habitat":"urban","captureRate":190,"growthRate":"medium","eggGroups":["mineral"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Usually found in power plants. Easily mistaken for a POKé BALL, they have zapped many people."},{"game":"yellow","text":"It is said to camouflage itself as a POKé BALL. It will self-destruct with very little stimulus."},{"game":"gold","text":"It rolls to move. If the ground is uneven, a sudden jolt from hitting a bump can cause it to explode."}],"source":"pokeapi"},{"speciesId":101,"genus":"Ball Pokémon","habitat":"urban","captureRate":60,"growthRate":"medium","eggGroups":["mineral"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"It stores electric energy under very high pressure. It often explodes with little or no provocation."},{"game":"yellow","text":"Stores electrical energy inside its body. Even the slightest shock could trigger a huge explosion."},{"game":"gold","text":"It is dangerous. If it has too much electricity and has nothing to do, it amuses itself by exploding."}],"source":"pokeapi"},{"speciesId":102,"genus":"Egg Pokémon","habitat":"forest","captureRate":90,"growthRate":"slow","eggGroups":["plant"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"silver","text":"Using telepathy only they can receive, they always form a cluster of six EXEGGCUTE."},{"game":"red","text":"Often mistaken for eggs. When disturbed, they quickly gather and attack in swarms."},{"game":"yellow","text":"The heads attract each other and spin around. There must be 6 heads for it to maintain balance."}],"source":"pokeapi"},{"speciesId":103,"genus":"Coconut Pokémon","habitat":"forest","captureRate":45,"growthRate":"slow","eggGroups":["plant"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Legend has it that on rare occasions, one of its heads will drop off and continue on as an EXEGGCUTE."},{"game":"yellow","text":"Its cries are very noisy. This is because each of the 3 heads thinks about whatever it likes."},{"game":"gold","text":"Its three heads think independent­ ly. However, they are friendly and never appear to squabble."}],"source":"pokeapi"},{"speciesId":104,"genus":"Lonely Pokémon","habitat":"mountain","captureRate":190,"growthRate":"medium","eggGroups":["monster"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Because it never removes its skull helmet, no one has ever seen this POKéMON's real face."},{"game":"yellow","text":"Wears the skull of its deceased mother. Its cries echo inside the skull and come out as a sad melody."},{"game":"gold","text":"If it is sad or lonely, the skull it wears shakes, and emits a plain­ tive and mournful sound."}],"source":"pokeapi"},{"speciesId":105,"genus":"Bone Keeper Pokémon","habitat":"mountain","captureRate":75,"growthRate":"medium","eggGroups":["monster"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"The bone it holds is its key weapon. It throws the bone skillfully like a boomerang to KO targets."},{"game":"yellow","text":"Small and weak, this POKéMON is adept with its bone club. It has grown more vicious over the ages."},{"game":"gold","text":"It has been seen pounding boulders with the bone it carries in order to tap out mes­ sages to others."}],"source":"pokeapi"},{"speciesId":106,"genus":"Kicking Pokémon","habitat":"urban","captureRate":45,"growthRate":"medium","eggGroups":["humanshape"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"When in a hurry, its legs lengthen progressively. It runs smoothly with extra long, loping strides."},{"game":"yellow","text":"When kicking, the sole of its foot turns as hard as a diamond on im­ pact and destroys its enemy."},{"game":"gold","text":"This amazing POKé­ MON has an awesome sense of balance. It can kick in succession from any position."}],"source":"pokeapi"},{"speciesId":107,"genus":"Punching Pokémon","habitat":"urban","captureRate":45,"growthRate":"medium","eggGroups":["humanshape"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"pearl","text":"The arm-twisting punches it throws pulverize even concrete. It rests after three minutes of fighting."},{"game":"red","text":"While apparently doing nothing, it fires punches in lightning fast volleys that are impossible to see."},{"game":"yellow","text":"Punches in cork­ screw fashion. It can punch its way through a concrete wall in the same way as a drill."}],"source":"pokeapi"},{"speciesId":108,"genus":"Licking Pokémon","habitat":"grassland","captureRate":45,"growthRate":"medium","eggGroups":["monster"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Its tongue can be extended like a chameleon's. It leaves a tingling sensation when it licks enemies."},{"game":"yellow","text":"Its tongue spans almost 7 feet and moves more freely than its forelegs. Its licks can cause paralysis."},{"game":"gold","text":"Its tongue has well-developed nerves that run to the very tip, so it can be deft­ ly manipulated."}],"source":"pokeapi"},{"speciesId":109,"genus":"Poison Gas Pokémon","habitat":"urban","captureRate":190,"growthRate":"medium","eggGroups":["indeterminate"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Because it stores several kinds of toxic gases in its body, it is prone to exploding without warning."},{"game":"yellow","text":"In hot places, its internal gases could expand and explode without any warning. Be very careful!"},{"game":"gold","text":"Its thin, filmy body is filled with gases that cause constant sniffles, coughs and teary eyes."}],"source":"pokeapi"},{"speciesId":110,"genus":"Poison Gas Pokémon","habitat":"urban","captureRate":60,"growthRate":"medium","eggGroups":["indeterminate"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Where two kinds of poison gases meet, 2 KOFFINGs can fuse into a WEEZING over many years."},{"game":"yellow","text":"It lives and grows by absorbing dust, germs and poison gases that are contained in toxic waste and garbage."},{"game":"gold","text":"If one of the twin KOFFING inflates, the other one deflates. It con­ stantly mixes its poisonous gases."}],"source":"pokeapi"},{"speciesId":111,"genus":"Spikes Pokémon","habitat":"rough-terrain","captureRate":120,"growthRate":"slow","eggGroups":["monster","ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Its massive bones are 1000 times harder than human bones. It can easily knock a trailer flying."},{"game":"yellow","text":"A POKéMON with a one-track mind. Once it charges, it won't stop running until it falls asleep."},{"game":"gold","text":"It is inept at turning because of its four short legs. It can only charge and run in one direction."}],"source":"pokeapi"},{"speciesId":112,"genus":"Drill Pokémon","habitat":"rough-terrain","captureRate":60,"growthRate":"slow","eggGroups":["monster","ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Protected by an armor-like hide, it is capable of living in molten lava of 3,600 degrees."},{"game":"yellow","text":"Walks on its hind legs. Shows signs of intelligence. Its armor-like hide even repels molten lava."},{"game":"gold","text":"Its rugged hide protects it from even the heat of lava. However, the hide also makes it insensitive."}],"source":"pokeapi"},{"speciesId":113,"genus":"Egg Pokémon","habitat":"urban","captureRate":30,"growthRate":"fast","eggGroups":["fairy"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"A rare and elusive POKéMON that is said to bring happiness to those who manage to get it."},{"game":"yellow","text":"A gentle and kind­ hearted POKéMON that shares its nutritious eggs if it sees an injured POKéMON."},{"game":"gold","text":"It walks carefully to prevent its egg from breaking. However, it is extremely fast at running away."}],"source":"pokeapi"},{"speciesId":114,"genus":"Vine Pokémon","habitat":"grassland","captureRate":45,"growthRate":"medium","eggGroups":["plant"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"The whole body is swathed with wide vines that are similar to sea­ weed. Its vines shake as it walks."},{"game":"yellow","text":"Its identity is obscured by masses of thick, blue vines. The vines are said to never stop growing."},{"game":"gold","text":"The vines that cloak its entire body are always jiggling. They effectively un­ nerve its foes."}],"source":"pokeapi"},{"speciesId":115,"genus":"Parent Pokémon","habitat":"grassland","captureRate":45,"growthRate":"medium","eggGroups":["monster"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"The infant rarely ventures out of its mother's protective pouch until it is 3 years old."},{"game":"yellow","text":"Raises its young in its belly pouch. Won't run from any fight to keep its young protected."},{"game":"gold","text":"If it is safe, the young gets out of the belly pouch to play. The adult keeps a close eye on the youngster."}],"source":"pokeapi"},{"speciesId":116,"genus":"Dragon Pokémon","habitat":"sea","captureRate":225,"growthRate":"medium","eggGroups":["water1","dragon"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Known to shoot down flying bugs with precision blasts of ink from the surface of the water."},{"game":"yellow","text":"If it senses any danger, it will vigorously spray water or a special type of ink from its mouth."},{"game":"gold","text":"If attacked by a larger enemy, it quickly swims to safety by adeptly controlling its dorsal fin."}],"source":"pokeapi"},{"speciesId":117,"genus":"Dragon Pokémon","habitat":"sea","captureRate":75,"growthRate":"medium","eggGroups":["water1","dragon"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Capable of swim­ ming backwards by rapidly flapping its wing-like pectoral fins and stout tail."},{"game":"yellow","text":"Touching the back fin causes numb­ ness. It hooks its tail to coral to stay in place while sleeping."},{"game":"gold","text":"An examination of its cells revealed the presence of a gene not found in HORSEA. It became a hot topic."}],"source":"pokeapi"},{"speciesId":118,"genus":"Goldfish Pokémon","habitat":"waters-edge","captureRate":225,"growthRate":"medium","eggGroups":["water2"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Its tail fin billows like an elegant ballroom dress, giving it the nickname of the Water Queen."},{"game":"yellow","text":"When it is time for them to lay eggs, they can be seen swimming up rivers and falls in large groups."},{"game":"gold","text":"Its dorsal, pecto­ ral and tail fins wave elegantly in water. That is why it is known as the water dancer."}],"source":"pokeapi"},{"speciesId":119,"genus":"Goldfish Pokémon","habitat":"waters-edge","captureRate":60,"growthRate":"medium","eggGroups":["water2"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"white-2","text":"In autumn, its body becomes more fatty in preparing to propose to a mate. It takes on beautiful colors."},{"game":"red","text":"In the autumn spawning season, they can be seen swimming power­ fully up rivers and creeks."},{"game":"yellow","text":"It is the male's job to make a nest by carving out boulders in a stream using the horn on its head."}],"source":"pokeapi"},{"speciesId":120,"genus":"Star Shape Pokémon","habitat":"sea","captureRate":225,"growthRate":"slow","eggGroups":["water3"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"An enigmatic POKéMON that can effortlessly regenerate any appendage it loses in battle."},{"game":"yellow","text":"As long as the center section is unharmed, it can grow back fully even if it is chopped to bits."},{"game":"gold","text":"At night, the cen­ ter of its body slowly flickers with the same rhythm as a human heartbeat."}],"source":"pokeapi"},{"speciesId":121,"genus":"Mysterious Pokémon","habitat":"sea","captureRate":60,"growthRate":"slow","eggGroups":["water3"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Its central core glows with the seven colors of the rainbow. Some people value the core as a gem."},{"game":"yellow","text":"The center section is named the core. People think it is communicating when it glows in 7 colors."},{"game":"gold","text":"The center section of its body is called the core. It glows in a dif­ ferent color each time it is seen."}],"source":"pokeapi"},{"speciesId":122,"genus":"Barrier Pokémon","habitat":"urban","captureRate":45,"growthRate":"medium","eggGroups":["humanshape"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"If interrupted while it is miming, it will slap around the offender with its broad hands."},{"game":"yellow","text":"Always practices its pantomime act. It makes enemies believe something exists that really doesn't."},{"game":"gold","text":"A skilled mime from birth, it gains the ability to create invisi­ ble objects as it matures."}],"source":"pokeapi"},{"speciesId":123,"genus":"Mantis Pokémon","habitat":"grassland","captureRate":45,"growthRate":"medium","eggGroups":["bug"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"With ninja-like agility and speed, it can create the illusion that there is more than one."},{"game":"yellow","text":"Leaps out of tall grass and slices prey with its scythes. The move­ ment looks like that of a ninja."},{"game":"gold","text":"It slashes through grass with its sharp scythes, moving too fast for the human eye to track."}],"source":"pokeapi"},{"speciesId":124,"genus":"Human Shape Pokémon","habitat":"urban","captureRate":45,"growthRate":"medium","eggGroups":["humanshape"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"It seductively wiggles its hips as it walks. It can cause people to dance in unison with it."},{"game":"yellow","text":"Appears to move to a rhythm of its own, as if it were dancing. It wiggles its hips as it walks."},{"game":"gold","text":"It rocks its body rhythmically. It appears to alter the rhythm depend­ ing on how it is feeling."}],"source":"pokeapi"},{"speciesId":125,"genus":"Electric Pokémon","habitat":"grassland","captureRate":45,"growthRate":"medium","eggGroups":["humanshape"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Normally found near power plants, they can wander away and cause major blackouts in cities."},{"game":"yellow","text":"If a major power outage occurs, it is certain that this POKéMON has eaten electricity at a power plant."},{"game":"gold","text":"Electricity runs across the surface of its body. In darkness, its en­ tire body glows a whitish-blue."}],"source":"pokeapi"},{"speciesId":126,"genus":"Spitfire Pokémon","habitat":"mountain","captureRate":45,"growthRate":"medium","eggGroups":["humanshape"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Its body always burns with an orange glow that enables it to hide perfectly among flames."},{"game":"yellow","text":"Born in an active volcano. Its body is always cloaked in flames, so it looks like a big ball of fire."},{"game":"gold","text":"It dislikes cold places, so it blows scorching flames to make the environment suit­ able for itself."}],"source":"pokeapi"},{"speciesId":127,"genus":"Stag Beetle Pokémon","habitat":"forest","captureRate":45,"growthRate":"slow","eggGroups":["bug"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"If it fails to crush the victim in its pincers, it will swing it around and toss it hard."},{"game":"yellow","text":"Grips its prey in its pincers and squeezes hard! It can't move if it's cold, so it lives in warm places."},{"game":"gold","text":"With its horns, it digs burrows to sleep in at night. In the morning, damp soil clings to its body."}],"source":"pokeapi"},{"speciesId":128,"genus":"Wild Bull Pokémon","habitat":"grassland","captureRate":45,"growthRate":"slow","eggGroups":["ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"When it targets an enemy, it charges furiously while whipping its body with its long tails."},{"game":"yellow","text":"A rowdy POKéMON with a lot of stamina. Once running, it won't stop until it hits something."},{"game":"gold","text":"They fight each other by locking horns. The herd's protector takes pride in its bat­ tle-scarred horns."}],"source":"pokeapi"},{"speciesId":129,"genus":"Fish Pokémon","habitat":"waters-edge","captureRate":255,"growthRate":"slow","eggGroups":["water2","dragon"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"In the distant past, it was somewhat stronger than the horribly weak descendants that exist today."},{"game":"yellow","text":"Famous for being very unreliable. It can be found swimming in seas, lakes, rivers and shallow puddles."},{"game":"gold","text":"An underpowered, pathetic POKéMON. It may jump high on rare occasions, but never more than seven feet."}],"source":"pokeapi"},{"speciesId":130,"genus":"Atrocious Pokémon","habitat":"waters-edge","captureRate":45,"growthRate":"slow","eggGroups":["water2","dragon"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Rarely seen in the wild. Huge and vicious, it is capable of destroying entire cities in a rage."},{"game":"yellow","text":"Brutally vicious and enormously destructive. Known for totally destroying cities in ancient times."},{"game":"gold","text":"They say that during past wars, GYARADOS would appear and leave blazing ruins in its wake."}],"source":"pokeapi"},{"speciesId":131,"genus":"Transport Pokémon","habitat":"sea","captureRate":45,"growthRate":"slow","eggGroups":["monster","water1"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"A POKéMON that has been over­ hunted almost to extinction. It can ferry people across the water."},{"game":"yellow","text":"A gentle soul that can read the minds of people. It can ferry people across the sea on its back."},{"game":"gold","text":"They have gentle hearts. Because they rarely fight, many have been caught. Their num­ ber has dwindled."}],"source":"pokeapi"},{"speciesId":132,"genus":"Transform Pokémon","habitat":"urban","captureRate":35,"growthRate":"medium","eggGroups":["ditto"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"lets-go-pikachu","text":"When it spots an enemy, its body transfigures into an almost-perfect copy of its opponent."},{"game":"red","text":"Capable of copying an enemy's genetic code to instantly transform itself into a duplicate of the enemy."},{"game":"yellow","text":"When it spots an enemy, its body transfigures into an almost perfect copy of its oppo­ nent."}],"source":"pokeapi"},{"speciesId":133,"genus":"Evolution Pokémon","habitat":"urban","captureRate":45,"growthRate":"medium","eggGroups":["ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Its genetic code is irregular. It may mutate if it is exposed to radiation from element STONEs."},{"game":"yellow","text":"Its genetic code is unstable, so it could evolve in a variety of ways. There are only a few alive."},{"game":"gold","text":"It has the ability to alter the com­ position of its body to suit its surrounding envi­ ronment."}],"source":"pokeapi"},{"speciesId":134,"genus":"Bubble Jet Pokémon","habitat":"urban","captureRate":45,"growthRate":"medium","eggGroups":["ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Lives close to water. Its long tail is ridged with a fin which is often mistaken for a mermaid's."},{"game":"yellow","text":"Its cell structure is similar to water molecules. It will melt away and become invis­ ible in water."},{"game":"gold","text":"When VAPOREON's fins begin to vi­ brate, it is a sign that rain will come within a few hours."}],"source":"pokeapi"},{"speciesId":135,"genus":"Lightning Pokémon","habitat":"urban","captureRate":45,"growthRate":"medium","eggGroups":["ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"It accumulates negative ions in the atmosphere to blast out 10000- volt lightning bolts."},{"game":"yellow","text":"A sensitive POKé­ MON that easily becomes sad or angry. Every time its mood changes, it charges power."},{"game":"gold","text":"It concentrates the weak electric charges emitted by its cells and launches wicked lightning bolts."}],"source":"pokeapi"},{"speciesId":136,"genus":"Flame Pokémon","habitat":"urban","captureRate":45,"growthRate":"medium","eggGroups":["ground"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"When storing thermal energy in its body, its temperature could soar to over 1600 degrees."},{"game":"yellow","text":"It has a flame chamber inside its body. It inhales, then blows out fire that is over 3,000F degrees."},{"game":"gold","text":"It stores some of the air it inhales in its internal flame pouch, which heats it to over 3,000 degrees."}],"source":"pokeapi"},{"speciesId":137,"genus":"Virtual Pokémon","habitat":"urban","captureRate":45,"growthRate":"medium","eggGroups":["mineral"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"A POKéMON that consists entirely of programming code. Capable of moving freely in cyberspace."},{"game":"yellow","text":"The only POKéMON people anticipate can fly into space. None has managed the feat yet, however."},{"game":"gold","text":"It is a manmade POKéMON. Since it doesn't breathe, people are eager to try it in any environment."}],"source":"pokeapi"},{"speciesId":138,"genus":"Spiral Pokémon","habitat":"sea","captureRate":45,"growthRate":"medium","eggGroups":["water1","water3"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Although long extinct, in rare cases, it can be genetically resurrected from fossils."},{"game":"yellow","text":"An ancient POKéMON that was recovered from a fossil. It swims by cleverly twisting its 10 tentacles about."},{"game":"gold","text":"Revived from an ancient fossil, this POKéMON uses air stored in its shell to sink and rise in water."}],"source":"pokeapi"},{"speciesId":139,"genus":"Spiral Pokémon","habitat":"sea","captureRate":45,"growthRate":"medium","eggGroups":["water1","water3"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"A prehistoric POKéMON that died out when its heavy shell made it impossible to catch prey."},{"game":"yellow","text":"Sharp beaks ring its mouth. Its shell was too big for it to move freely, so it became extinct."},{"game":"gold","text":"Apparently, it cracked SHELLDER's shell with its sharp fangs and sucked out the insides."}],"source":"pokeapi"},{"speciesId":140,"genus":"Shellfish Pokémon","habitat":"sea","captureRate":45,"growthRate":"medium","eggGroups":["water1","water3"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"A POKéMON that was resurrected from a fossil found in what was once the ocean floor eons ago."},{"game":"yellow","text":"A POKéMON that was recovered from a fossil. It uses the eyes on its back while hiding on the sea floor."},{"game":"gold","text":"On rare occasions, some have been found as fossils which they became while hiding on the ocean floor."}],"source":"pokeapi"},{"speciesId":141,"genus":"Shellfish Pokémon","habitat":"sea","captureRate":45,"growthRate":"medium","eggGroups":["water1","water3"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"sword","text":"Kabutops slices its prey apart and sucks out the fluids. The discarded body parts become food for other Pokémon."},{"game":"red","text":"Its sleek shape is perfect for swim­ ming. It slashes prey with its claws and drains the body fluids."},{"game":"yellow","text":"A slim and fast swimmer. It slices its prey with its sharp sickles and drinks the body fluids."}],"source":"pokeapi"},{"speciesId":142,"genus":"Fossil Pokémon","habitat":"mountain","captureRate":45,"growthRate":"slow","eggGroups":["flying"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"A ferocious, pre­ historic POKéMON that goes for the enemy's throat with its serrated saw-like fangs."},{"game":"yellow","text":"A savage POKéMON that died out in ancient times. It was resurrected using DNA taken from amber."},{"game":"gold","text":"A vicious POKéMON from the distant past, it appears to have flown by spreading its wings and gliding."}],"source":"pokeapi"},{"speciesId":143,"genus":"Sleeping Pokémon","habitat":"mountain","captureRate":25,"growthRate":"slow","eggGroups":["monster"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Very lazy. Just eats and sleeps. As its rotund bulk builds, it becomes steadily more slothful."},{"game":"yellow","text":"Will eat anything, even if the food happens to be a little moldy. It never gets an upset stomach."},{"game":"gold","text":"What sounds like its cry may ac­ tually be its snores or the rumblings of its hungry belly."}],"source":"pokeapi"},{"speciesId":144,"genus":"Freeze Pokémon","habitat":"rare","captureRate":3,"growthRate":"slow","eggGroups":["no-eggs"],"isLegendary":true,"isMythical":false,"pokedexEntries":[{"game":"red","text":"A legendary bird POKéMON that is said to appear to doomed people who are lost in icy mountains."},{"game":"yellow","text":"A legendary bird POKéMON. It freezes water that is contained in winter air and makes it snow."},{"game":"gold","text":"The magnificent, seemingly translu­ cent wings of this legendary bird POKéMON are said to be made of ice."}],"source":"pokeapi"},{"speciesId":145,"genus":"Electric Pokémon","habitat":"rare","captureRate":3,"growthRate":"slow","eggGroups":["no-eggs"],"isLegendary":true,"isMythical":false,"pokedexEntries":[{"game":"red","text":"A legendary bird POKéMON that is said to appear from clouds while dropping enormous lightning bolts."},{"game":"yellow","text":"This legendary bird POKéMON is said to appear when the sky turns dark and lightning showers down."},{"game":"gold","text":"This legendary bird POKéMON causes savage thunderstorms by flapping its glit­ tering wings."}],"source":"pokeapi"},{"speciesId":146,"genus":"Flame Pokémon","habitat":"rare","captureRate":3,"growthRate":"slow","eggGroups":["no-eggs"],"isLegendary":true,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Known as the legendary bird of fire. Every flap of its wings creates a dazzling flash of flames."},{"game":"yellow","text":"A legendary bird POKéMON. As it flaps its flaming wings, even the night sky will turn red."},{"game":"gold","text":"This legendary POKéMON scatters embers with every flap of its wings. It is a thrilling sight to behold."}],"source":"pokeapi"},{"speciesId":147,"genus":"Dragon Pokémon","habitat":"waters-edge","captureRate":45,"growthRate":"slow","eggGroups":["water1","dragon"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"Long considered a mythical POKéMON until recently when a small colony was found living underwater."},{"game":"yellow","text":"The existence of this mythical POKéMON was only recently confirmed by a fisherman who caught one."},{"game":"gold","text":"It is born large to start with. It repeatedly sheds its skin as it steadily grows longer."}],"source":"pokeapi"},{"speciesId":148,"genus":"Dragon Pokémon","habitat":"waters-edge","captureRate":45,"growthRate":"slow","eggGroups":["water1","dragon"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"A mystical POKéMON that exudes a gentle aura. Has the ability to change climate conditions."},{"game":"yellow","text":"According to a witness, its body was surrounded by a strange aura that gave it a mystical look."},{"game":"gold","text":"They say that if it emits an aura from its whole body, the weather will begin to change instantly."}],"source":"pokeapi"},{"speciesId":149,"genus":"Dragon Pokémon","habitat":"waters-edge","captureRate":45,"growthRate":"slow","eggGroups":["water1","dragon"],"isLegendary":false,"isMythical":false,"pokedexEntries":[{"game":"red","text":"An extremely rarely seen marine POKéMON. Its intelligence is said to match that of humans."},{"game":"yellow","text":"It is said that this POKéMON lives somewhere in the sea and that it flies. However, it is only a rumor."},{"game":"gold","text":"It is said that this POKéMON con­ stantly flies over the immense seas and rescues drown­ ing people."}],"source":"pokeapi"},{"speciesId":150,"genus":"Genetic Pokémon","habitat":"rare","captureRate":3,"growthRate":"slow","eggGroups":["no-eggs"],"isLegendary":true,"isMythical":false,"pokedexEntries":[{"game":"red","text":"It was created by a scientist after years of horrific gene splicing and DNA engineering experiments."},{"game":"yellow","text":"Its DNA is almost the same as MEW's. However, its size and disposition are vastly dif­ ferent."},{"game":"gold","text":"Because its battle abilities were raised to the ultimate level, it thinks only of de­ feating its foes."}],"source":"pokeapi"},{"speciesId":151,"genus":"New Species Pokémon","habitat":"rare","captureRate":45,"growthRate":"medium-slow","eggGroups":["no-eggs"],"isLegendary":false,"isMythical":true,"pokedexEntries":[{"game":"red","text":"So rare that it is still said to be a mirage by many experts. Only a few people have seen it worldwide."},{"game":"yellow","text":"When viewed through a micro­ scope, this POKéMON's short, fine, delicate hair can be seen."},{"game":"gold","text":"Apparently, it appears only to those people who are pure of heart and have a strong desire to see it."}],"source":"pokeapi"}];
